defmodule SessionAuth do
  @moduledoc false

  import Plug.Conn

  def login(conn, user_id, session_data \\ %{}) do
    session = SessionManager.new(user_id, session_data)
    SessionDistributedStore.store_session(session.id, session)
    
    SessionCookieStore.put_session(conn, session)
  end

  def logout(conn) do
    case SessionCookieStore.get_session(conn) do
      {:ok, session} ->
        SessionDistributedStore.delete_session(session.id)
        SessionCookieStore.delete_session(conn)
      
      _ ->
        SessionCookieStore.delete_session(conn)
    end
  end

